-- ============================================================================
-- Quiz Seed: 2 Kings — Part 1 (Chapters 1–10)
-- 3 difficulties × 10 chapters = 160 total questions
-- ============================================================================

-- ═══ 2 Kings Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 1, 'kids', 1, 'What happened to King Ahaziah that caused him to be injured?', 'He fell through a lattice in his upper chamber', 'He was struck by an arrow in battle', 'He fell off his horse', 'He was pushed by his servants', 'a', '2 Kings 1:2 — "And Ahaziah fell down through a lattice in his upper chamber that was in Samaria, and was sick."'),
('2 Kings', 1, 'kids', 2, 'What god did King Ahaziah send messengers to ask about his sickness?', 'Baal-zebub the god of Ekron', 'Dagon the god of the Philistines', 'Molech the god of the Ammonites', 'Baal of Peor', 'a', '2 Kings 1:2 — "Go, enquire of Baal-zebub the god of Ekron whether I shall recover of this disease."'),
('2 Kings', 1, 'kids', 3, 'What did Elijah call down from heaven when the captain commanded him to come down?', 'Fire', 'Rain', 'Thunder', 'Wind', 'a', '2 Kings 1:10 — "And Elijah answered and said to the captain of fifty, If I be a man of God, then let fire come down from heaven and consume thee and thy fifty. And there came down fire from heaven."'),
-- Teens
('2 Kings', 1, 'teens', 1, 'What message did the angel of the LORD tell Elijah to give Ahaziah''s messengers?', 'Is it not because there is not a God in Israel that thou sendest to Baal-zebub?', 'Thus saith the LORD, thou shalt not recover of this disease', 'Return to the king and tell him he shall live', 'The LORD is angry and will destroy the king''s household', 'a', '2 Kings 1:3 — "Is it not because there is not a God in Israel, that ye go to enquire of Baal-zebub the god of Ekron?"'),
('2 Kings', 1, 'teens', 2, 'How did the king''s messengers describe Elijah to Ahaziah when they returned?', 'A hairy man with a leather girdle about his loins', 'A bald man with a staff of wood', 'A tall man clothed in white linen', 'An old man wearing a rough mantle', 'a', '2 Kings 1:8 — "He was an hairy man, and girt with a girdle of leather about his loins. And he said, It is Elijah the Tishbite."'),
('2 Kings', 1, 'teens', 3, 'What happened to the first two captains of fifty who were sent to Elijah?', 'They were consumed by fire from heaven', 'They were struck blind', 'They were swallowed by the earth', 'They fled in fear', 'a', '2 Kings 1:10,12 — Fire came down from heaven and consumed both the first and second captain and their fifties.'),
('2 Kings', 1, 'teens', 4, 'What did the third captain of fifty do differently from the first two captains?', 'He fell on his knees and begged Elijah for mercy', 'He threatened Elijah with his sword', 'He brought gifts of silver and gold', 'He called on the name of Baal', 'a', '2 Kings 1:13 — "The third captain of fifty went up, and came and fell on his knees before Elijah, and besought him, and said unto him, O man of God, I pray thee, let my life, and the life of these fifty thy servants, be precious in thy sight."'),
('2 Kings', 1, 'teens', 5, 'What was the fulfillment of Elijah''s prophecy concerning Ahaziah?', 'He died according to the word of the LORD', 'He recovered from his disease', 'He was killed in battle against Moab', 'He was deposed by his brother Jehoram', 'a', '2 Kings 1:17 — "So he died according to the word of the LORD which Elijah had spoken."'),
-- Adults
('2 Kings', 1, 'adults', 1, 'What was the political context surrounding Ahaziah''s fall — what had happened with Moab at the start of this chapter?', 'Moab rebelled against Israel after the death of Ahab', 'Moab sent tribute to Israel as in prior years', 'Moab invaded Israel from the east', 'Moab formed an alliance with Syria against Israel', 'a', '2 Kings 1:1 — "Then Moab rebelled against Israel after the death of Ahab."'),
('2 Kings', 1, 'adults', 2, 'What divine instruction did the angel of the LORD give Elijah before he intercepted the messengers?', 'Arise, go up to meet the messengers of the king of Samaria', 'Go and stand before the king in the gate of Samaria', 'Flee to the brook Cherith and hide thyself', 'Take a coal from the altar and go to Ahab', 'a', '2 Kings 1:3 — "But the angel of the LORD said to Elijah the Tishbite, Arise, go up to meet the messengers of the king of Samaria."'),
('2 Kings', 1, 'adults', 3, 'What exact prophecy did Elijah deliver to Ahaziah''s messengers regarding the king''s fate?', 'Thou shalt not come down from that bed on which thou art gone up, but shalt surely die', 'The LORD will smite thee with a sore disease till thy dying day', 'Thy kingdom shall be taken from thee and given to another', 'The sword shall not depart from thine house for ever', 'a', '2 Kings 1:4 — "Now therefore thus saith the LORD, Thou shalt not come down from that bed on which thou art gone up, but shalt surely die."'),
('2 Kings', 1, 'adults', 4, 'What words did the first captain use to summon Elijah, and what was Elijah''s response?', 'Thou man of God, the king hath said, Come down; Elijah called fire from heaven', 'Prophet of God, come to the palace; Elijah refused and stayed seated', 'Man of God, surrender yourself; Elijah fled to Carmel', 'Holy man, speak to the king; Elijah prayed and remained silent', 'a', '2 Kings 1:9-10 — "Thou man of God, the king hath said, Come down. And Elijah answered and said... let fire come down from heaven and consume thee and thy fifty."'),
('2 Kings', 1, 'adults', 5, 'How does the narrative contrast the plea of the third captain with those of the first two?', 'He humbled himself and asked for his life to be precious in Elijah''s sight, and the angel of the LORD told Elijah to go with him', 'He brought a written decree from the king demanding Elijah''s compliance', 'He came with only ten men instead of fifty to show no threat', 'He appealed to the covenant of Carmel as justification', 'a', '2 Kings 1:13-15 — The third captain fell on his knees and begged, and the angel of the LORD told Elijah: "Go down with him: be not afraid of him."'),
('2 Kings', 1, 'adults', 6, 'What does Elijah''s direct speech to Ahaziah underscore about the king''s fundamental failure?', 'He had sought Baal-zebub because there was no God in Israel to enquire of', 'He had failed to build the temple of Baal properly', 'He had not offered the required burnt offerings to God', 'He had rejected the counsel of Elijah''s school of prophets', 'a', '2 Kings 1:16 — "Forasmuch as thou hast sent messengers to enquire of Baal-zebub the god of Ekron, is it not because there is no God in Israel to enquire of his word?"'),
('2 Kings', 1, 'adults', 7, 'Who succeeded Ahaziah as king, and why did Ahaziah have no son to succeed him?', 'Jehoram his brother, because Ahaziah had no son', 'Jehu, because Ahaziah''s son was slain in battle', 'Athaliah, because Ahaziah died without an heir', 'Joash, because Ahaziah''s sons were hidden from Athaliah', 'a', '2 Kings 1:17 — "And Jehoram reigned in his stead in the second year of Jehoram the son of Jehoshaphat king of Judah; because he had no son."'),
('2 Kings', 1, 'adults', 8, 'In what source does 2 Kings 1:18 say the rest of Ahaziah''s acts are written?', 'The book of the chronicles of the kings of Israel', 'The book of Jasher', 'The annals of the prophets of Samaria', 'The book of the acts of Solomon', 'a', '2 Kings 1:18 — "Now the rest of the acts of Ahaziah which he did, are they not written in the book of the chronicles of the kings of Israel?"');

-- ═══ 2 Kings Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 2, 'kids', 1, 'How was Elijah taken up to heaven?', 'In a chariot of fire and a whirlwind', 'In a cloud of glory', 'On the wings of eagles', 'By a mighty rushing wind', 'a', '2 Kings 2:11 — "And Elijah went up by a whirlwind into heaven."'),
('2 Kings', 2, 'kids', 2, 'What did Elisha pick up from the ground after Elijah was taken to heaven?', 'Elijah''s mantle', 'Elijah''s staff', 'Elijah''s sandals', 'Elijah''s belt', 'a', '2 Kings 2:13 — "He took up also the mantle of Elijah that fell from him."'),
('2 Kings', 2, 'kids', 3, 'What happened when Elisha struck the waters of the Jordan with Elijah''s mantle?', 'The waters divided so he could cross', 'The waters turned to blood', 'The waters dried up completely', 'The waters began to flow backwards', 'a', '2 Kings 2:14 — "And he smote the waters, and they parted hither and thither: and Elisha went over."'),
-- Teens
('2 Kings', 2, 'teens', 1, 'What one thing did Elisha ask of Elijah before he was taken away?', 'A double portion of thy spirit upon me', 'That he would remain in Israel always', 'That the sons of the prophets would follow him', 'That the LORD would speak to him at Horeb', 'a', '2 Kings 2:9 — "Elisha said, I pray thee, let a double portion of thy spirit be upon me."'),
('2 Kings', 2, 'teens', 2, 'What condition did Elijah place on Elisha''s request for a double portion?', 'If thou see me when I am taken from thee, it shall be so unto thee', 'If thou fast forty days as Moses did, it shall be granted', 'If the sons of the prophets confirm thy calling, thou shalt receive it', 'If thou return to Jordan and dip thyself seven times', 'a', '2 Kings 2:10 — "If thou see me when I am taken from thee, it shall be so unto thee; but if not, it shall not be so."'),
('2 Kings', 2, 'teens', 3, 'How did Elisha heal the waters of Jericho that were bad and caused the land to be barren?', 'He cast salt into the spring', 'He prayed over the waters for three days', 'He struck the waters with his mantle', 'He poured oil upon the waters', 'a', '2 Kings 2:21 — "And he went forth unto the spring of the waters, and cast the salt in there, and said, Thus saith the LORD, I have healed these waters."'),
('2 Kings', 2, 'teens', 4, 'What mocking words did the young men of Bethel say to Elisha?', 'Go up, thou bald head; go up, thou bald head', 'Go back to Gilgal, prophet of Elijah', 'We have no need of thy miracles here', 'Get thee hence, old man, and trouble us not', 'a', '2 Kings 2:23 — "And there came forth little children out of the city, and mocked him, and said unto him, Go up, thou bald head; go up, thou bald head."'),
('2 Kings', 2, 'teens', 5, 'What animals came out of the wood and tore forty-two of the mocking youths?', 'Two she bears', 'Two lions', 'A great bear', 'Wolves from the wilderness', 'a', '2 Kings 2:24 — "And there came forth two she bears out of the wood, and tare forty and two children of them."'),
-- Adults
('2 Kings', 2, 'adults', 1, 'Which three locations did Elijah and Elisha visit together before Elijah''s translation, in order?', 'Gilgal, Bethel, Jericho, then Jordan', 'Bethel, Gilgal, Samaria, then Carmel', 'Jericho, Bethel, Gilgal, then Jordan', 'Jordan, Jericho, Bethel, then Gilgal', 'a', '2 Kings 2:1-6 — Elijah and Elisha went from Gilgal to Bethel, then to Jericho, and then to the Jordan.'),
('2 Kings', 2, 'adults', 2, 'How many prophets from the sons of the prophets stood watching from afar when Elijah and Elisha crossed the Jordan?', 'Fifty men', 'Seven men', 'One hundred men', 'Twelve men', 'a', '2 Kings 2:7 — "And fifty men of the sons of the prophets went, and stood to view afar off."'),
('2 Kings', 2, 'adults', 3, 'With what did Elijah smite the Jordan waters before the translation, and what happened?', 'He smote the waters with his mantle and they divided, and both went over on dry ground', 'He cried to the LORD and the waters parted as at the Exodus', 'He stretched his staff over the waters as Moses at the Red Sea', 'He anointed the waters with oil and they became shallow', 'a', '2 Kings 2:8 — "And Elijah took his mantle, and wrapped it together, and smote the waters, and they were divided hither and thither, so that they two went over on dry ground."'),
('2 Kings', 2, 'adults', 4, 'What did Elisha cry as he witnessed Elijah''s ascent, and what did he do to his own garment?', 'My father, my father, the chariot of Israel and the horsemen thereof — he rent his own clothes in two pieces', 'Elijah, Elijah, take me with thee — he tore his hair', 'Thus Israel is left without a prophet — he prostrated himself', 'LORD God, receive thy servant — he covered his face with his mantle', 'a', '2 Kings 2:12 — "And he saw him no more: and he took hold of his own clothes, and rent them in two pieces."'),
('2 Kings', 2, 'adults', 5, 'What did the fifty sons of the prophets insist on doing after Elijah''s translation, and what was the result?', 'They searched three days for Elijah but could not find him', 'They went to the Jordan and prayed for seven days', 'They declared Elisha to be the new chief prophet at once', 'They anointed Elisha at Jericho the same day', 'a', '2 Kings 2:17 — "And they sought three days, but found him not."'),
('2 Kings', 2, 'adults', 6, 'What theological significance is attached to Elisha asking for a double portion of Elijah''s spirit?', 'It was the customary birthright request of the firstborn son, signifying Elisha as Elijah''s spiritual heir', 'It was a request for twice Elijah''s power to defeat Syria', 'It meant Elisha wanted to perform twice as many miracles as Moses', 'It reflected a rabbinical tradition requiring two prophets in each generation', 'a', '2 Kings 2:9 — A "double portion" echoes Deuteronomy 21:17, where the firstborn receives double inheritance, marking Elisha as Elijah''s chief prophetic successor.'),
('2 Kings', 2, 'adults', 7, 'How did the sons of the prophets at Jericho recognize that the spirit of Elijah rested upon Elisha?', 'They saw him divide the Jordan waters and came to meet him and bowed before him', 'They heard a voice from heaven declaring his calling', 'They witnessed fire descend on him as at Carmel', 'An angel announced his prophetic succession to them', 'a', '2 Kings 2:15 — "And when the sons of the prophets which were to view at Jericho saw him, they said, The spirit of Elijah doth rest on Elisha. And they came to meet him, and bowed themselves to the ground before him."'),
('2 Kings', 2, 'adults', 8, 'What prophetic word accompanied Elisha''s healing of Jericho''s waters, and is it recorded as being permanently fulfilled?', 'Thus saith the LORD, I have healed these waters; there shall not be from thence any more death or barren land — and the waters were healed unto this day', 'God will restore the spring if the people repent — and the waters returned after seven years', 'The waters are healed for one generation — and the land flourished for forty years', 'Drink of these waters and live — and no man died of thirst in Jericho again', 'a', '2 Kings 2:21-22 — "Thus saith the LORD, I have healed these waters; there shall not be from thence any more death or barren land. So the waters were healed unto this day."');

-- ═══ 2 Kings Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 3, 'kids', 1, 'Which prophet did Jehoram, Jehoshaphat, and the king of Edom go to seek guidance from?', 'Elisha', 'Elijah', 'Isaiah', 'Micaiah', 'a', '2 Kings 3:11 — "But Jehoshaphat said, Is there not here a prophet of the LORD, that we may enquire of the LORD by him? And one of the king of Israel''s servants answered and said, Here is Elisha the son of Shaphat."'),
('2 Kings', 3, 'kids', 2, 'What did Elisha ask for before he would prophesy, saying he needed it to play before him?', 'A minstrel', 'A torch', 'A scroll', 'A lamb', 'a', '2 Kings 3:15 — "But now bring me a minstrel. And it came to pass, when the minstrel played, that the hand of the LORD came upon him."'),
('2 Kings', 3, 'kids', 3, 'What did God miraculously provide in the valley for the armies who had no water?', 'Water filled the valley', 'Dew covered the ground', 'A spring burst from the rock', 'Rain fell all night', 'a', '2 Kings 3:17,20 — God promised water without wind or rain, and in the morning water filled the country.'),
-- Teens
('2 Kings', 3, 'teens', 1, 'Why did Mesha king of Moab rebel against Israel?', 'The king of Israel refused to pay him tribute any longer after Ahab''s death', 'Moab had been forced to pay one hundred thousand lambs and rams with wool to Israel, and rebelled after Ahab died', 'The Israelites had taken Moabite land for their cattle', 'Mesha''s son was killed by Israelite soldiers', 'a', '2 Kings 3:4-5 — "And Mesha king of Moab was a sheepmaster, and rendered unto the king of Israel an hundred thousand lambs, and an hundred thousand rams, with the wool. But it came to pass, when Ahab was dead, that the king of Moab rebelled against the king of Israel."'),
('2 Kings', 3, 'teens', 2, 'Through which nation''s wilderness did the three kings take a seven-day march to attack Moab?', 'The wilderness of Edom', 'The wilderness of Judah', 'The wilderness of Sinai', 'The wilderness of Moab', 'a', '2 Kings 3:8-9 — Jehoshaphat chose the way through the wilderness of Edom, and the three kings went round seven days'' journey.'),
('2 Kings', 3, 'teens', 3, 'What did Elisha tell the kings to do in the valley so that water would come?', 'Make this valley full of ditches', 'Pray at the riverside three times', 'Strike the ground with their weapons', 'Dig a well in the centre of the camp', 'a', '2 Kings 3:16 — "Thus saith the LORD, Make this valley full of ditches."'),
('2 Kings', 3, 'teens', 4, 'Why did the Moabites mistake the water in the valley for blood when they saw it in the morning?', 'The sun shone upon the water and it appeared red to the Moabites', 'The water reflected the red clay of the valley walls', 'The bodies of slain soldiers had stained the water', 'The water mixed with red desert sand overnight', 'a', '2 Kings 3:22 — "And they rose up early in the morning, and the sun shone upon the water, and the Moabites saw the water on the other side as red as blood."'),
('2 Kings', 3, 'teens', 5, 'What desperate act did Mesha king of Moab perform when he saw the battle was going against him?', 'He offered his eldest son as a burnt offering upon the wall', 'He sent five hundred horsemen to break through to Edom', 'He surrendered to Jehoshaphat and sued for peace', 'He called on Chemosh to destroy the enemy armies', 'a', '2 Kings 3:27 — "Then he took his eldest son that should have reigned in his stead, and offered him for a burnt offering upon the wall."'),
-- Adults
('2 Kings', 3, 'adults', 1, 'What was Jehoram son of Ahab''s moral assessment in 2 Kings 3, and how did he differ from his parents?', 'He did evil but put away the image of Baal that his father had made, though he cleaved unto the sins of Jeroboam', 'He did right in the sight of the LORD but worshipped the golden calves', 'He was the most wicked of all the kings of Israel', 'He served Baal as his mother did and also worshipped Jeroboam''s calves', 'a', '2 Kings 3:2-3 — "He wrought evil in the sight of the LORD; but not like his father, and like his mother... he put away the image of Baal that his father had made. Nevertheless he cleaved unto the sins of Jeroboam the son of Nebat."'),
('2 Kings', 3, 'adults', 2, 'What harsh rebuke did Elisha give Jehoram before agreeing to prophesy, and what was his reason for helping at all?', 'He said he would not help Jehoram but respected Jehoshaphat''s presence and prophesied for his sake', 'He demanded the king repent of Baal worship before he would speak', 'He refused to see Jehoram and sent his message by a servant', 'He said the famine was sent by God and he would not intercede for Israel', 'a', '2 Kings 3:13-14 — "What have I to do with thee? get thee to the prophets of thy father... As the LORD of hosts liveth, before whom I stand, surely, were it not that I regard the presence of Jehoshaphat the king of Judah, I would not look toward thee, nor see thee."'),
('2 Kings', 3, 'adults', 3, 'What twofold promise did Elisha deliver on behalf of the LORD to the three kings?', 'Ye shall not see wind, neither shall ye see rain; yet that valley shall be filled with water, and ye shall smite every fenced city and every choice city', 'The LORD will give you victory by morning, and Mesha shall be delivered into your hand', 'The valley will overflow and Moab shall flee before you without a battle', 'Send your armies at dawn and the water will come, though many will fall in the wilderness', 'a', '2 Kings 3:17-19 — "Ye shall not see wind, neither shall ye see rain; yet that valley shall be filled with water... and ye shall smite every fenced city, and every choice city."'),
('2 Kings', 3, 'adults', 4, 'What actions did the Israelite army take against Moabite cities and land in fulfillment of Elisha''s prophecy?', 'They beat down the cities, cast stones on every good piece of land, stopped all wells of water, and felled all good trees', 'They burned all the cities and took the cattle and goods as spoil', 'They destroyed only the capital city and left the rest of Moab intact', 'They salted all the fields and left the cities standing as a warning', 'a', '2 Kings 3:25 — "And they beat down the cities, and on every good piece of land cast every man his stone, and filled it; and they stopped all the wells of water, and felled all the good trees."'),
('2 Kings', 3, 'adults', 5, 'What was the result of Mesha''s human sacrifice of his son upon the wall regarding the Israelite campaign?', 'There was great indignation against Israel and they departed from him and returned to their own land', 'The Israelites were energized by righteous anger and took the city immediately', 'The Moabites surrendered at once, horrified by their king''s act', 'The three-king alliance broke apart in disagreement over the sacrifice', 'a', '2 Kings 3:27 — "And there was great indignation against Israel: and they departed from him, and returned to their own land."'),
('2 Kings', 3, 'adults', 6, 'What does the role of music played before Elisha reveal about prophetic practice in the Hebrew tradition?', 'Music was used to create a receptive state for prophetic inspiration, as the hand of the LORD came upon Elisha when the minstrel played', 'Music was purely ceremonial and had no connection to the prophetic gift', 'Elisha required music only because he was deaf and needed to concentrate', 'Music served to drive away evil spirits before prophecy could occur', 'a', '2 Kings 3:15 — "But now bring me a minstrel. And it came to pass, when the minstrel played, that the hand of the LORD came upon him."'),
('2 Kings', 3, 'adults', 7, 'How did the confederacy of kings come about for this campaign against Moab?', 'Jehoram of Israel allied with Jehoshaphat of Judah and the king of Edom and went by the way of the wilderness of Edom', 'The three kings were summoned by the prophet Elisha to fight Moab', 'Jehoshaphat proposed a direct northern route but Jehoram insisted on the Edom wilderness', 'The king of Edom approached Jehoram independently after Moab attacked his borders', 'a', '2 Kings 3:7-8 — Jehoram asked Jehoshaphat who agreed to join, and Jehoshaphat chose the way through the wilderness of Edom, so the king of Edom joined them.'),
('2 Kings', 3, 'adults', 8, 'What was the theological tension in the chapter between Israel''s military success and the ultimate outcome, and what does it suggest about Chemosh worship?', 'The military campaign was largely successful yet ended inconclusively after Mesha''s sacrifice, suggesting the narrative preserves historical ambiguity without glorifying pagan religion', 'The narrative shows Chemosh was more powerful than the LORD in this instance', 'The ending proves that human sacrifice was effective in Moabite religion', 'Elisha''s prophecy was partially false since Israel did not complete the destruction of Moab', 'a', '2 Kings 3:19,27 — Elisha prophesied total victory, yet after Mesha''s sacrifice "there was great indignation against Israel" and they withdrew, showing the narrative''s honest complexity.');

-- ═══ 2 Kings Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 4, 'kids', 1, 'In the story of the widow''s oil, what did Elisha tell her to do with the empty vessels she borrowed?', 'Pour her small pot of oil into all the borrowed vessels', 'Wash them and bring them to the temple', 'Fill them with water and pray over them', 'Sell them to buy food', 'a', '2 Kings 4:4 — "And when thou art come in, thou shalt shut the door upon thee and upon thy sons, and shalt pour out into all those vessels."'),
('2 Kings', 4, 'kids', 2, 'What happened to the widow''s oil when she kept pouring it into the borrowed vessels?', 'It kept flowing until all the vessels were full, then stopped', 'It doubled in amount each time she poured', 'It turned into gold', 'It ran out after she filled three vessels', 'a', '2 Kings 4:6 — "And it came to pass, when the vessels were full, that she said unto her son, Bring me yet a vessel. And he said unto her, There is not a vessel more. And the oil stayed."'),
('2 Kings', 4, 'kids', 3, 'Whose son did Elisha raise back to life in this chapter?', 'The Shunammite woman''s son', 'The widow''s son at Zarephath', 'A son of one of the prophets', 'Naaman''s young son', 'a', '2 Kings 4:36 — "And he called Gehazi, and said, Call this Shunammite. So he called her. And when she was come in unto him, he said, Take up thy son."'),
-- Teens
('2 Kings', 4, 'teens', 1, 'What did the Shunammite woman provide for Elisha whenever he passed by?', 'Bread, and she set a little chamber with a bed, table, stool, and candlestick for him', 'A portion of the temple offering and a place at her table', 'Oil and grain for the prophets'' school at Carmel', 'A new robe and sandals each year', 'a', '2 Kings 4:10 — "Let us make a little chamber, I pray thee, on the wall; and let us set for him there a bed, and a table, and a stool, and a candlestick."'),
('2 Kings', 4, 'teens', 2, 'What reward did Elisha promise the Shunammite woman for her hospitality?', 'That she would embrace a son in the coming year', 'That her husband would be healed of his old age', 'That her family would never know famine', 'That her house would stand for a hundred years', 'a', '2 Kings 4:16 — "And he said, About this season, according to the time of life, thou shalt embrace a son."'),
('2 Kings', 4, 'teens', 3, 'What did the Shunammite woman say to her husband when she left to find Elisha after her son died?', 'It shall be well', 'The man of God will save our son', 'Do not weep, God is faithful', 'I will not return without the prophet', 'a', '2 Kings 4:23 — "And her husband said to her, Wherefore wilt thou go to him to day?... And she said, It shall be well."'),
('2 Kings', 4, 'teens', 4, 'What did Elisha do to raise the Shunammite''s dead son?', 'He lay upon the child, putting his mouth and hands upon him, and the child''s flesh grew warm and he sneezed seven times', 'He prayed over the child and touched his head with oil', 'He called down fire from heaven upon the child''s body', 'He cast the child into the Jordan and commanded him to rise', 'a', '2 Kings 4:34-35 — "And he went up, and lay upon the child, and put his mouth upon his mouth, and his eyes upon his eyes... and the child sneezed seven times."'),
('2 Kings', 4, 'teens', 5, 'What was the problem with the pottage Elisha''s servant made at Gilgal, and how was it fixed?', 'There was death in the pot from wild gourds, and Elisha cast in meal and it was made wholesome', 'The water was too salty, so Elisha added fresh water from the spring', 'The bread was mouldy and Elisha blessed it so it became fresh', 'There was a serpent in the pot, and Elisha removed it by prayer', 'a', '2 Kings 4:40-41 — "There is death in the pot. And he said, Then bring meal. And he cast it into the pot; and he said, Pour out for the people, that they may eat. And there was no harm in the pot."'),
-- Adults
('2 Kings', 4, 'adults', 1, 'What debt crisis was the widow of a prophet''s son facing, and what did Elisha learn she possessed?', 'Creditors were coming to take her two sons as bondservants, and she had nothing in the house save a pot of oil', 'She owed the temple tax and her husband''s burial debts, and had only barley and water', 'Her sons were to be sold for the price of a field, and she had one talent of silver', 'The king''s tax collector demanded everything and she had only her two sons left', 'a', '2 Kings 4:1-2 — "The creditor is come to take unto him my two sons to be bondmen... And she said, Thine handmaid hath not any thing in the house, save a pot of oil."'),
('2 Kings', 4, 'adults', 2, 'What was the precise instruction Elisha gave the widow regarding the borrowed vessels and the door?', 'Shut the door upon thee and thy sons, pour into all the vessels, and set aside every full one', 'Gather the vessels secretly, fill them at night, and bring them to Elisha in the morning', 'Open the door wide for your neighbours, pour as all the sons help, and give praise to God', 'Fill the vessels by day, bring them before the priests, and sell them in the market', 'a', '2 Kings 4:4 — "And when thou art come in, thou shalt shut the door upon thee and upon thy sons, and shalt pour out into all those vessels, and thou shalt set aside that which is full."'),
('2 Kings', 4, 'adults', 3, 'How does Elisha''s exchange with the Shunammite woman reveal his prophetic knowledge about her deepest longing?', 'He perceived by enquiry through Gehazi that she had no child and her husband was old, so he promised her a son', 'She directly asked for a son and Elisha consulted the LORD before answering', 'He saw a vision of a child in her arms and declared it to her', 'The sons of the prophets told him she was barren, and he interceded on her behalf', 'a', '2 Kings 4:14 — "And he said, What then is to be done for her? And Gehazi answered, Verily she hath no child, and her husband is old."'),
('2 Kings', 4, 'adults', 4, 'What did the Shunammite woman''s son cry out before dying, and when did the death occur?', 'He said "My head, my head" to his father, was carried home to his mother, and sat on her knees till noon when he died', 'He cried out in the field at dawn and was carried to Elisha by servants', 'He fell at Elisha''s feet saying he was dying, and Elisha prayed over him immediately', 'He was silent but grew pale; he died at sunset in the guest chamber', 'a', '2 Kings 4:19-20 — "And he said unto his father, My head, my head... And he sat on her knees till noon, and then died."'),
('2 Kings', 4, 'adults', 5, 'What was Elisha''s first attempt to raise the child through Gehazi, and why was it insufficient?', 'He sent Gehazi with his staff to lay upon the child''s face, but there was neither voice nor hearing, so the child was not awaked', 'He prayed for the child from a distance but the LORD had not yet answered', 'He anointed the child with oil by proxy through Gehazi but the child remained cold', 'He commanded Gehazi to carry the child to the Jordan and dip him in the water', 'a', '2 Kings 4:31 — "And Gehazi passed on before them, and laid the staff upon the face of the child; but there was neither voice, nor hearing. Wherefore he went again to meet him, and told him, saying, The child is not awaked."'),
('2 Kings', 4, 'adults', 6, 'In the bread-multiplication miracle, what was the quantity of food brought and the number fed?', 'Twenty loaves of barley and full ears of corn in the husk fed a hundred men with bread to spare', 'Five loaves and two fish fed five thousand men', 'Two loaves of wheat bread fed fifty sons of the prophets', 'Twelve cakes of unleavened bread fed seventy men at Gilgal', 'a', '2 Kings 4:42-44 — "There came a man from Baal-shalisha, and brought the man of God bread of the firstfruits, twenty loaves of barley... Set before the people, that they may eat... So he set it before them, and they did eat, and left thereof, according to the word of the LORD."'),
('2 Kings', 4, 'adults', 7, 'How does the Shunammite''s response to Elisha''s questioning after her son''s death demonstrate her faith?', 'She said "It is well" three times and clung to his feet, unwilling to leave without help, showing absolute trust', 'She wept and told Elisha plainly that her son was dead and demanded resurrection', 'She rebuked Elisha for Gehazi''s failure and asked why God had taken her son', 'She prayed aloud and recited the promises of God before requesting Elisha''s intervention', 'a', '2 Kings 4:26 — "Is it well with thee? is it well with thy husband? is it well with the child? And she answered, It is well."'),
('2 Kings', 4, 'adults', 8, 'What wild plant caused the deadly pottage and what does the text say the sons of prophets gathered in error?', 'Wild gourds from a wild vine, gathered by a man who did not know what they were', 'Hemlock from the fields of Gilgal mixed into the stew', 'Poisonous mushrooms gathered in the forest of Bethel', 'Bitter herbs of the wilderness that resembled edible plants', 'a', '2 Kings 4:39 — "And one went out into the field to gather herbs, and found a wild vine, and gathered thereof wild gourds his lap full, and came and shred them into the pot of pottage: for they knew them not."');

-- ═══ 2 Kings Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 5, 'kids', 1, 'What disease did the great Syrian commander Naaman have?', 'Leprosy', 'Blindness', 'Lameness', 'A fever', 'a', '2 Kings 5:1 — "Now Naaman, captain of the host of the king of Syria, was a great man... but he was a leper."'),
('2 Kings', 5, 'kids', 2, 'How many times did Elisha tell Naaman to dip himself in the Jordan River to be healed?', 'Seven times', 'Three times', 'Once', 'Forty times', 'a', '2 Kings 5:10 — "And Elisha sent a messenger unto him, saying, Go and wash in Jordan seven times, and thy flesh shall come again to thee, and thou shalt be clean."'),
('2 Kings', 5, 'kids', 3, 'What punishment did Elisha''s greedy servant Gehazi receive for secretly taking gifts from Naaman?', 'The leprosy of Naaman came upon him', 'He was struck blind', 'He was cast out of Elisha''s house forever', 'He was handed over to the king of Syria', 'a', '2 Kings 5:27 — "The leprosy therefore of Naaman shall cleave unto thee, and unto thy seed for ever. And he went out from his presence a leper as white as snow."'),
-- Teens
('2 Kings', 5, 'teens', 1, 'Who first told Naaman about the prophet in Israel who could heal him?', 'A little Israelite maid who served Naaman''s wife', 'The king of Syria''s chief counsellor', 'A priest of Rimmon who had heard of Elisha', 'A merchant from Samaria passing through Damascus', 'a', '2 Kings 5:2-3 — "And the Syrians had brought away captive out of the land of Israel a little maid; and she waited on Naaman''s wife. And she said unto her mistress, Would God my lord were with the prophet that is in Samaria! for he would recover him of his leprosy."'),
('2 Kings', 5, 'teens', 2, 'Why was the king of Israel distressed when he received the king of Syria''s letter about Naaman?', 'He said, Am I God, to kill and to make alive, that this man doth send unto me to recover a man of his leprosy?', 'He feared it was a trick to start war with Syria', 'He did not know who the prophet Elisha was', 'He had just declared war on Syria and feared the timing', 'a', '2 Kings 5:7 — "And it came to pass, when the king of Israel had read the letter, that he rent his clothes, and said, Am I God, to kill and to make alive, that this man doth send unto me to recover a man of his leprosy?"'),
('2 Kings', 5, 'teens', 3, 'Why was Naaman initially angry with Elisha''s instructions to wash in the Jordan?', 'He expected Elisha to come out personally, call on his God''s name, and strike his hand over the place, not just send a servant to tell him to wash in a common river', 'He thought the Jordan was too cold and dangerous to dip in seven times', 'He believed only the rivers of Damascus were holy enough to cleanse a leper', 'He was insulted that Elisha demanded payment before healing him', 'a', '2 Kings 5:11-12 — "Behold, I thought, He will surely come out to me... Are not Abana and Pharpar, rivers of Damascus, better than all the waters of Israel?"'),
('2 Kings', 5, 'teens', 4, 'After being healed, what did Naaman declare about the God of Israel?', 'Behold, now I know that there is no God in all the earth, but in Israel', 'The LORD alone is God and all other gods are nothing', 'Blessed be the name of the LORD God of Israel who heals the leper', 'There is none like Elisha and there is none like his God', 'a', '2 Kings 5:15 — "And he returned to the man of God, he and all his company, and came, and stood before him: and he said, Behold, now I know that there is no God in all the earth, but in Israel."'),
('2 Kings', 5, 'teens', 5, 'What did Gehazi lie about to Naaman, and how much did he request?', 'He said Elisha sent him to ask for a talent of silver and two changes of garments', 'He said Elisha had fallen sick and needed medicine from Syria', 'He claimed the sons of the prophets needed gold for a new meeting house', 'He told Naaman that Elisha had changed his mind and would accept the gifts', 'a', '2 Kings 5:22 — "And Gehazi said, My master hath sent me, saying, Behold, even now there be come to me from mount Ephraim two young men of the sons of the prophets: give them, I pray thee, a talent of silver, and two changes of garments."'),
-- Adults
('2 Kings', 5, 'adults', 1, 'What was the full description of Naaman''s status and why was it theologically significant that "by him the LORD had given deliverance unto Syria"?', 'He was a great man, honourable, and mighty in valour — yet the LORD used a pagan general as his instrument of deliverance, showing divine sovereignty over nations', 'He was the wealthiest man in Syria and his riches proved the LORD blessed pagans', 'His greatness was earned entirely through personal merit with no divine involvement', 'He was great because he secretly worshipped the God of Israel while serving the Syrian king', 'a', '2 Kings 5:1 — "Now Naaman, captain of the host of the king of Syria, was a great man with his master, and honourable... by him the LORD had given deliverance unto Syria."'),
('2 Kings', 5, 'adults', 2, 'What specific tribute did the king of Syria send with Naaman to the king of Israel, and what did his letter demand?', 'Ten talents of silver, six thousand pieces of gold, ten changes of raiment; the letter demanded the king of Israel recover Naaman of his leprosy', 'One thousand talents of silver and a letter demanding military alliance', 'The firstfruits of Syria''s harvest and a request for Elisha to visit Damascus', 'Gifts of horses and chariots and a letter seeking a peace treaty', 'a', '2 Kings 5:5-6 — "And he took with him ten talents of silver, and six thousand pieces of gold, and ten changes of raiment... Now when this letter is come unto thee, behold, I have therewith sent Naaman my servant to thee, that thou mayest recover him of his leprosy."'),
('2 Kings', 5, 'adults', 3, 'How did Elisha hear that the king of Israel had rent his clothes, and what message did he send to the king?', 'He heard it and said, Wherefore hast thou rent thy clothes? let him come now to me, and he shall know that there is a prophet in Israel', 'A servant ran to Carmel and told Elisha, who then went to the king''s palace immediately', 'The spirit of God told Elisha in a vision and he sent an angel to the palace', 'Gehazi reported the king''s distress and Elisha wrote a letter to the court', 'a', '2 Kings 5:8 — "And it was so, when Elisha the man of God had heard that the king of Israel had rent his clothes, that he sent to the king, saying, Wherefore hast thou rent thy clothes? let him come now to me, and he shall know that there is a prophet in Israel."'),
('2 Kings', 5, 'adults', 4, 'What persuaded Naaman to overcome his pride and dip in the Jordan despite his initial anger?', 'His servants reasoned with him that if the prophet had asked a great thing he would have done it, so how much more should he do a simple thing', 'The king of Israel threatened him with imprisonment if he refused', 'Naaman saw a vision of the LORD commanding him to obey Elisha', 'Elisha himself appeared and rebuked Naaman for his stubbornness', 'a', '2 Kings 5:13 — "And his servants came near, and spake unto him, and said, My father, if the prophet had bid thee do some great thing, wouldest thou not have done it? how much more then, when he saith to thee, Wash, and be clean?"'),
('2 Kings', 5, 'adults', 5, 'What theological request did Naaman make regarding a load of earth, and what pardon did he request concerning bowing in the house of Rimmon?', 'He asked for two mules'' burden of earth to offer burnt offerings only to the LORD, and sought pardon for bowing in Rimmon''s temple when supporting his master', 'He asked to take a stone from the Jordan as a memorial and permission to keep his Syrian idols', 'He asked to build an altar to the LORD in Damascus using stones from Israel', 'He requested to be circumcised and observe all the laws of Moses in Syria', 'a', '2 Kings 5:17-18 — "Thy servant will henceforth offer neither burnt offering nor sacrifice unto other gods, but unto the LORD. In this thing the LORD pardon thy servant, that when my master goeth into the house of Rimmon to worship there... the LORD pardon thy servant in this thing."'),
('2 Kings', 5, 'adults', 6, 'How did Elisha know what Gehazi had done, and what does his question to Gehazi reveal about prophetic insight?', 'He asked "Went not mine heart with thee?" showing he had spiritual perception of Gehazi''s secret journey to Naaman', 'Naaman returned to Elisha and reported Gehazi''s deception the same day', 'A servant of Elisha who accompanied Gehazi secretly reported back to his master', 'The LORD sent an angel to Elisha in a dream that same night', 'a', '2 Kings 5:26 — "And he said unto him, Went not mine heart with thee, when the man turned again from his chariot to meet thee?"'),
('2 Kings', 5, 'adults', 7, 'What items did Naaman eagerly press upon Gehazi beyond what Gehazi requested?', 'He urged him and bound two talents of silver in two bags with two changes of garments and gave them to two of his servants who carried them before Gehazi', 'He added his own military sword and armour to the gifts', 'He sent Gehazi back with a full chariot of gold and silver', 'He insisted on sending ten servants to Elisha''s house with the gifts', 'a', '2 Kings 5:23 — "And Naaman said, Be content, take two talents. And he urged him, and bound two talents of silver in two bags, with two changes of garments."'),
('2 Kings', 5, 'adults', 8, 'What does the curse pronounced on Gehazi''s descendants reveal about the moral seriousness of exploiting prophetic ministry for personal gain?', 'The leprosy would cleave to him and his seed forever, showing that betraying the integrity of God''s ministry brings perpetual consequences', 'It shows that leprosy was always hereditary in Israel''s legal code', 'It demonstrates that God punishes only the greedy and not the foolish', 'It reveals that Elisha had the power to curse families independently of God''s will', 'a', '2 Kings 5:27 — "The leprosy therefore of Naaman shall cleave unto thee, and unto thy seed for ever. And he went out from his presence a leper as white as snow."');

-- ═══ 2 Kings Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 6, 'kids', 1, 'When one of the sons of the prophets dropped an axe head into the Jordan River, what miracle did Elisha perform?', 'He made the iron axe head float to the surface', 'He reached into the water and retrieved it', 'He prayed and the river dried up so they could find it', 'He made a new axe head from wood', 'a', '2 Kings 6:6 — "And he cut down a stick, and cast it in thither; and the iron did swim."'),
('2 Kings', 6, 'kids', 2, 'What did Elisha''s servant see surrounding them when God opened his eyes on the mountain?', 'Horses and chariots of fire all around', 'A great army of angels with swords', 'A cloud of glory filling the valley', 'Mighty winds protecting the camp', 'a', '2 Kings 6:17 — "And the LORD opened the eyes of the young man; and he saw: and, behold, the mountain was full of horses and chariots of fire round about Elisha."'),
('2 Kings', 6, 'kids', 3, 'What did Elisha pray for the Syrian army that had come to capture him, so that he could lead them to Samaria?', 'That God would smite them with blindness', 'That God would send fire to destroy them', 'That God would terrify them with thunder', 'That God would make them fall asleep', 'a', '2 Kings 6:18 — "And Elisha prayed unto the LORD, and said, Smite this people, I pray thee, with blindness. And he smote them with blindness according to the word of Elisha."'),
-- Teens
('2 Kings', 6, 'teens', 1, 'Why was the son of the prophets distressed about the axe head that fell into the Jordan?', 'It was borrowed, so he could not afford to replace it', 'It was a sacred implement used in the prophets'' school', 'He had stolen it from his master and feared punishment', 'It was the only axe they had and winter was coming', 'a', '2 Kings 6:5 — "But as one was felling a beam, the axe head fell into the water: and he cried, and said, Alas, master! for it was borrowed."'),
('2 Kings', 6, 'teens', 2, 'How did Elisha know where the Syrian king was planning his secret military movements?', 'God told Elisha what the king of Syria said in his bedchamber', 'Elisha had spies in the Syrian court', 'A Syrian defector gave the information to the king of Israel', 'The sons of the prophets at Dothan observed the Syrian army movements', 'a', '2 Kings 6:12 — "And one of his servants said, None, my lord, O king: but Elisha, the prophet that is in Israel, telleth the king of Israel the words that thou speakest in thy bedchamber."'),
('2 Kings', 6, 'teens', 3, 'What was Elisha''s prayer for his frightened servant on the mountain, and how was it answered?', 'He prayed for his servant''s eyes to be opened, and the servant saw the mountain full of horses and chariots of fire', 'He prayed for peace in the servant''s heart and the servant was comforted by a vision', 'He prayed for the servant to be hidden from the Syrian army below', 'He prayed that the servant would be made bold and the servant charged down the hill', 'a', '2 Kings 6:17 — "And Elisha prayed, and said, LORD, I pray thee, open his eyes, that he may see... and he saw: and, behold, the mountain was full of horses and chariots of fire."'),
('2 Kings', 6, 'teens', 4, 'After leading the blind Syrian army to Samaria and God restored their sight, what did Elisha tell the king of Israel to do with the captives?', 'Set bread and water before them that they may eat and drink and go to their master', 'Put them to death as enemies of Israel', 'Hold them for ransom to be returned for peace', 'Make them servants of the prophets at Samaria', 'a', '2 Kings 6:22 — "And he answered, Thou shalt not smite them: wouldest thou smite those whom thou hast taken captive with thy sword and with thy bow? set bread and water before them, that they may eat and drink, and go to their master."'),
('2 Kings', 6, 'teens', 5, 'How severe was the famine during the Syrian siege of Samaria?', 'An ass''s head was sold for eighty pieces of silver and a cab of dove''s dung for five pieces', 'The people ate shoe leather and tree bark to survive', 'Three measures of barley were sold for a talent of gold', 'All the cattle were eaten and a loaf of bread cost a year''s wages', 'a', '2 Kings 6:25 — "And there was a great famine in Samaria: and, behold, they besieged it, until an ass''s head was sold for fourscore pieces of silver, and the fourth part of a cab of dove''s dung for five pieces of silver."'),
-- Adults
('2 Kings', 6, 'adults', 1, 'What was the purpose of the sons of the prophets going to the Jordan, and what problem arose with Elisha present?', 'They were building a dwelling place because their current place was too small, and one man''s borrowed axe head fell into the Jordan', 'They were baptizing new members of the school, and a man drowned in the Jordan', 'They went to gather reeds for the school''s construction, and the Jordan flooded', 'They sought to cross the Jordan, but a man lost his only tool in the crossing', 'a', '2 Kings 6:1-5 — "Let us go, we pray thee, unto Jordan, and take thence every man a beam... and as one was felling a beam, the axe head fell into the water."'),
('2 Kings', 6, 'adults', 2, 'What does the king of Syria''s response to discovering Elisha''s intelligence of his plans reveal about the prophetic threat Elisha posed?', 'He sent a great host with horses and chariots by night to surround Dothan to capture Elisha', 'He decided to make peace with Israel rather than fight a prophet he could not defeat', 'He placed a spy in Elisha''s school to report back his plans', 'He sent an assassin to kill Elisha in the night', 'a', '2 Kings 6:13-14 — "And he said, Go and spy where he is, that I may send and fetch him... Therefore sent he thither horses, and chariots, and a great host: and they came by night, and compassed the city about."'),
('2 Kings', 6, 'adults', 3, 'What was Elisha''s famous reassurance to his servant when the servant feared the surrounding Syrian army?', 'Fear not: for they that be with us are more than they that be with them', 'The LORD will fight for us and we shall hold our peace', 'Be still and know that I am God, and no weapon formed against thee shall prosper', 'The angel of the LORD encampeth round about them that fear him and delivereth them', 'a', '2 Kings 6:16 — "And he answered, Fear not: for they that be with us are more than they that be with them."'),
('2 Kings', 6, 'adults', 4, 'What is the theological significance of Elisha leading the blind Syrian army personally into Samaria, claiming he would "bring you to the man whom ye seek"?', 'Elisha used irony and divine control — he was the man they sought, yet led them to the king of Israel, demonstrating that God''s prophet is untouchable', 'Elisha was planning to surrender himself to end the siege', 'He led them there so the king of Israel could negotiate a ransom', 'He tricked them so the army of Israel could ambush them inside the city', 'a', '2 Kings 6:19 — "And Elisha said unto them, This is not the way, neither is this the city: follow me, and I will bring you to the man whom ye seek. But he led them to Samaria."'),
('2 Kings', 6, 'adults', 5, 'How did the incident with the captured Syrian army affect subsequent Syrian raids into Israel''s territory?', 'The bands of Syria came no more into the land of Israel', 'Syria intensified its raids and eventually besieged Samaria', 'The king of Syria signed a thirty-year peace treaty with Israel', 'Syria withdrew to fight the Assyrians instead', 'a', '2 Kings 6:23 — "So the bands of Syria came no more into the land of Israel."'),
('2 Kings', 6, 'adults', 6, 'What horrifying encounter did the king of Israel have with a woman during the siege that prompted him to tear his clothes?', 'A woman told him she had agreed to eat her son one day and her neighbour''s son the next, but the neighbour had hidden her son', 'A widow came to him saying Syrian soldiers had killed her whole family', 'A woman cried that she had no food for her children who were dying', 'A prophetess declared the king responsible for the siege through his sins', 'a', '2 Kings 6:28-29 — "And the king said unto her, What aileth thee? And she answered, This woman said unto me, Give thy son, that we may eat him to day, and we will eat my son to morrow. So we boiled my son, and did eat him: and I said unto her on the next day, Give thy son, that we may eat him: and she hath hid her son."'),
('2 Kings', 6, 'adults', 7, 'What vow did the king of Israel make in anger after hearing the woman''s story, and against whom was his fury directed?', 'He swore that God do so to him and more if Elisha''s head would stay on him that day, blaming Elisha for the famine', 'He vowed to fast until God ended the siege, and blamed himself for Israel''s sins', 'He declared war on the king of Syria and vowed vengeance on every Syrian city', 'He threatened the sons of the prophets with death for failing to end the siege', 'a', '2 Kings 6:31 — "Then he said, God do so and more also to me, if the head of Elisha the son of Shaphat shall stand on him this day."'),
('2 Kings', 6, 'adults', 8, 'What does Elisha''s awareness of the king''s murderous plan before the messenger arrived demonstrate in the narrative?', 'His prophetic knowledge was so exact that he addressed the elders and predicted the king''s arrival before the messenger reached the door', 'He received word from the palace guard who was loyal to him', 'The LORD sent an angel to warn him the previous night in a dream', 'Gehazi had overheard the king''s plan at the palace gate', 'a', '2 Kings 6:32 — "But Elisha sat in his house, and the elders sat with him; and the king sent a man from before him: but ere the messenger came to him, he said to the elders, See ye how this son of a murderer hath sent to take away mine head?"');

-- ═══ 2 Kings Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 7, 'kids', 1, 'Who discovered that the Syrian army had fled and left their camp empty?', 'Four lepers who went to the Syrian camp', 'The king''s servants who went at night', 'A watchman on the walls of Samaria', 'A boy sent by Elisha to spy on the camp', 'a', '2 Kings 7:3-5 — Four lepers at the gate of Samaria decided to go to the Syrian camp and when they arrived, there was no man there.'),
('2 Kings', 7, 'kids', 2, 'What had the LORD made the Syrian army hear that caused them to flee in panic?', 'A noise of chariots and horses and a great host', 'A voice from heaven commanding them to leave', 'A great earthquake that shook their camp', 'Thunder and lightning from the sky', 'a', '2 Kings 7:6 — "For the LORD had made the host of the Syrians to hear a noise of chariots, and a noise of horses, even the noise of a great host."'),
('2 Kings', 7, 'kids', 3, 'What did Elisha prophecy would happen to food prices in Samaria by the next day?', 'A measure of fine flour would sell for a shekel and two measures of barley for a shekel', 'All the food would be free for the poor of the city', 'The famine would end in seven days', 'God would send manna from heaven as in Moses'' time', 'a', '2 Kings 7:1 — "Then Elisha said, Hear ye the word of the LORD; Thus saith the LORD, To morrow about this time shall a measure of fine flour be sold for a shekel, and two measures of barley for a shekel, in the gate of Samaria."'),
-- Teens
('2 Kings', 7, 'teens', 1, 'What reasoning led the four lepers to go to the Syrian camp rather than stay at the city gate?', 'They said if they sat still they would die, and if they went into the city or the Syrian camp they might also die but there was a chance they would live', 'They had a vision from God directing them to the camp', 'They were expelled from the city by the king''s soldiers and had no choice', 'They heard there was food in the Syrian camp from a passing traveller', 'a', '2 Kings 7:3-4 — "If we say, We will enter into the city, then the famine is in the city, and we shall die there: and if we sit still here, we die also. Now therefore come, and let us fall unto the host of the Syrians."'),
('2 Kings', 7, 'teens', 2, 'What did the lepers find in the abandoned Syrian camp?', 'Tents with silver, gold, raiment, horses, and asses, and abundant food', 'Nothing but weapons and dead soldiers', 'Barley and flour but no valuables', 'Cattle and sheep penned in the camp', 'a', '2 Kings 7:8 — "And when these lepers came to the uttermost part of the camp, they went into one tent, and did eat and drink, and carried thence silver, and gold, and raiment, and went and hid it."'),
('2 Kings', 7, 'teens', 3, 'What did the lepers say to each other that prompted them to report to the city rather than keep the discovery to themselves?', 'We do not well: this day is a day of good tidings, and we hold our peace', 'God has given us this gift and we should share it with all', 'If we keep silent the king will punish us when he finds out', 'It is a sin to eat while our people are starving inside the walls', 'a', '2 Kings 7:9 — "Then they said one to another, We do not well: this day is a day of good tidings, and we hold our peace: if we tarry till the morning light, some mischief will come upon us."'),
('2 Kings', 7, 'teens', 4, 'What did the king of Israel initially suspect about the empty Syrian camp when he heard the report?', 'He said the Syrians have hidden themselves in the field, knowing Israel''s hunger, to catch them as they go out', 'He rejoiced and sent the whole army to plunder immediately', 'He thought the lepers were lying to trick him into an ambush', 'He believed it was a miracle of God and offered a burnt offering', 'a', '2 Kings 7:12 — "And the king arose in the night, and said unto his servants, I will now shew you what the Syrians have done to us. They know that we be hungry; therefore are they gone out of the camp to hide themselves in the field."'),
('2 Kings', 7, 'teens', 5, 'What happened to the officer who had doubted Elisha''s prophecy that food would be sold cheaply by the next day?', 'He was appointed to control the gate but the people trampled him in the rush and he died', 'He ate of the food and was struck down immediately by God', 'He was cast into prison for his unbelief', 'He fell sick and could not eat any of the food', 'a', '2 Kings 7:17,20 — "And the king appointed the lord on whose hand he leaned to have the charge of the gate: and the people trode upon him in the gate, and he died."'),
-- Adults
('2 Kings', 7, 'adults', 1, 'What was the exact doubting statement of the king''s officer in response to Elisha''s prophecy, and what was Elisha''s precise counter-prophecy?', 'He said "if the LORD would make windows in heaven, might this thing be?" and Elisha said he would see it with his eyes but not eat thereof', 'He said the prophecy was impossible and Elisha cursed him with sudden death', 'He demanded a sign from Elisha to verify the prophecy was from God', 'He laughed at Elisha and the prophet struck him dumb on the spot', 'a', '2 Kings 7:2 — "And a lord on whose hand the king leaned answered the man of God, and said, Behold, if the LORD would make windows in heaven, might this thing be? And he said, Behold, thou shalt see it with thine eyes, but shalt not eat thereof."'),
('2 Kings', 7, 'adults', 2, 'What caused the Syrian army to flee at night, and what two kings did they believe had been hired against them?', 'The LORD made them hear a noise of a great host, and they said the king of Israel had hired the Hittites and the kings of the Egyptians', 'An angel of death passed through their camp killing many soldiers', 'Elisha prayed for rain and the resulting flood drove them away', 'A great earthquake shook the camp and they interpreted it as divine judgment', 'a', '2 Kings 7:6 — "For the LORD had made the host of the Syrians to hear a noise of chariots... and they said one to another, Lo, the king of Israel hath hired against us the kings of the Hittites, and the kings of the Egyptians."'),
('2 Kings', 7, 'adults', 3, 'What intelligence-gathering method did the king employ before committing his forces to follow the Syrians?', 'He sent five horses that remained and messengers to spy out the Syrian road, and they found garments and vessels cast away along the entire route', 'He sent his best scout alone at night to determine if the camp was truly empty', 'He consulted Elisha before moving any soldiers from the city walls', 'He waited until dawn and sent a full battalion to verify the lepers'' report', 'a', '2 Kings 7:13-15 — "And they took therefore two chariot horses... and the king sent after the host of the Syrians... And the messengers returned, and told the king."'),
('2 Kings', 7, 'adults', 4, 'How does the narrative connect the doubting officer''s fate back to Elisha''s prophecy to demonstrate exact fulfillment?', 'Elisha had said he would see it but not eat thereof, and the people trampled him in the gate so he died, seeing the abundance but not partaking of it', 'The officer was excluded by the king from eating as punishment for his unbelief', 'God struck him with paralysis so he could not open his mouth to eat', 'He chose not to eat out of shame for doubting the prophet and starved', 'a', '2 Kings 7:19-20 — "And that lord answered the man of God... so it fell out unto him: for the people trode upon him in the gate, and he died."'),
('2 Kings', 7, 'adults', 5, 'What does the trajectory of the lepers in chapter 7 — from outcasts at the gate to heralds of salvation — suggest theologically?', 'God used the most marginalised people in society as instruments of deliverance for an entire city, reversing human expectations of who brings good news', 'The lepers were rewarded for their bravery with permanent healing from their disease', 'The narrative shows that lepers were given special prophetic gifts in times of crisis', 'Their role demonstrates that the king of Israel was too cowardly to act first', 'a', '2 Kings 7:9 — The lepers declared "this day is a day of good tidings" and brought the city-saving news, being the first to possess and share the liberation God had provided.'),
('2 Kings', 7, 'adults', 6, 'What was left behind as the Syrians fled, and what does the description of the abandoned road suggest about the speed and panic of their flight?', 'The Syrian camp was left with tents, horses, asses, and all provisions, and the road was strewn with garments and vessels cast aside in their haste', 'They took their horses but left their weapons and food', 'Only cooking implements were left; soldiers took everything of value', 'They destroyed their camp before leaving to prevent Israel from benefiting', 'a', '2 Kings 7:15 — "And they went after them unto Jordan: and, lo, all the way was full of garments and vessels, which the Syrians had cast away in their haste."'),
('2 Kings', 7, 'adults', 7, 'How does 2 Kings 7 relate to the broader theology of divine reversal in the book of Kings?', 'An impossible prophecy of abundance in the midst of extreme famine was fulfilled exactly within twenty-four hours, demonstrating the LORD''s sovereign power over both nature and armies', 'The chapter teaches that God rewards military courage and punishes cowardice', 'It shows that Syria was always destined to fail against Israel due to the Abrahamic covenant', 'The chapter primarily demonstrates that prophets must always be obeyed or face death', 'a', '2 Kings 7:1,16 — Elisha''s prophecy of flour and barley at normal prices was precisely fulfilled: "the people went out, and spoiled the tents of the Syrians. So a measure of fine flour was sold for a shekel."'),
('2 Kings', 7, 'adults', 8, 'What is the narrative function of the king''s night council in verses 12-14, and how does it build dramatic tension?', 'The king''s suspicion of a Syrian trap creates deliberate delay, heightening the drama before the messengers confirm the miracle and Elisha''s word is vindicated', 'The council scene serves only as a historical record of royal military procedure', 'It shows the king was wiser than Elisha and was right to be cautious', 'The scene demonstrates that democracy was practiced in ancient Israel', 'a', '2 Kings 7:12-15 — The king''s reasonable suspicion of ambush causes investigation before celebration, serving to authenticate the miraculous nature of the Syrian flight when the full scope of abandoned goods is found.');

-- ═══ 2 Kings Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 8, 'kids', 1, 'Elisha warned the Shunammite woman to leave the land because God was sending what for seven years?', 'A famine', 'A plague', 'War', 'Drought', 'a', '2 Kings 8:1 — "Then spake Elisha unto the woman, whose son he had restored to life, saying, Arise, and go thou and thine household, and sojourn wheresoever thou canst sojourn: for the LORD hath called for a famine; and it shall also come upon the land seven years."'),
('2 Kings', 8, 'kids', 2, 'When the Shunammite woman returned after seven years and asked the king for her house and land, who happened to be telling the king about Elisha''s miracles?', 'Gehazi, Elisha''s servant', 'A prophet from Bethel', 'One of the sons of the prophets', 'A scribe from the temple', 'a', '2 Kings 8:4-5 — "And the king talked with Gehazi the servant of the man of God, saying, Tell me, I pray thee, all the great things that Elisha hath done."'),
('2 Kings', 8, 'kids', 3, 'What did the Syrian king Ben-hadad send to Elisha to ask whether he would recover from his sickness?', 'Hazael with forty camel loads of gifts', 'Gold and silver by the hand of his servants', 'A peace offering and a written message', 'His chief priest with precious stones', 'a', '2 Kings 8:9 — "So Hazael went to meet him, and took a present with him, even of every good thing of Damascus, forty camels'' burden, and came and stood before him."'),
-- Teens
('2 Kings', 8, 'teens', 1, 'What happened to the Shunammite woman''s land while she was away during the seven-year famine?', 'It had been taken over, and when she appealed to the king he ordered it restored with all the fruits of the field since the day she left', 'It was sold to a neighbour and she had to buy it back', 'The king had claimed it as crown property during the famine', 'It was given to her relatives who refused to return it', 'a', '2 Kings 8:6 — "And when the king asked the woman, she told him. So the king appointed unto her a certain officer, saying, Restore all that was hers, and all the fruits of the field since the day that she left the land, even until now."'),
('2 Kings', 8, 'teens', 2, 'What did Elisha''s face do when he looked at Hazael, and what did he say would happen to Israel at Hazael''s hands?', 'He settled his countenance steadfastly upon him until he was ashamed, and wept because Hazael would do evil to Israel — burning cities, slaying young men, dashing infants, and ripping up women with child', 'He turned away in disgust and refused to speak to Hazael', 'He rejoiced and prophesied that Syria would become an ally of Israel', 'He was troubled and remained silent for a long time before speaking', 'a', '2 Kings 8:11-12 — "And he settled his countenance stedfastly, until he was ashamed: and the man of God wept. And Hazael said, Why weepeth my lord? And he answered, Because I know the evil that thou wilt do unto the children of Israel."'),
('2 Kings', 8, 'teens', 3, 'How did Hazael become king of Syria after returning from Elisha?', 'He smothered Ben-hadad with a wet cloth while he slept', 'He poisoned the king''s food at the royal banquet', 'He led a military coup and killed the king in his throne room', 'He waited until Ben-hadad died of his illness', 'a', '2 Kings 8:15 — "And it came to pass on the morrow, that he took a thick cloth, and dipped it in water, and spread it on his face, so that he died: and Hazael reigned in his stead."'),
('2 Kings', 8, 'teens', 4, 'What was the moral assessment of Jehoram king of Judah in this chapter?', 'He walked in the ways of the kings of Israel and did evil in the sight of the LORD', 'He did right in the sight of the LORD but not with a perfect heart', 'He was a man of God like David his father', 'He had no assessment given because he reigned only two years', 'a', '2 Kings 8:18 — "And he walked in the way of the kings of Israel, as did the house of Ahab: for the daughter of Ahab was his wife: and he did evil in the sight of the LORD."'),
('2 Kings', 8, 'teens', 5, 'Despite Jehoram''s wickedness, why did God not destroy Judah?', 'For David his servant''s sake, as the LORD said he would give him alway a light, and to his children', 'Because the people of Judah remained faithful to God', 'Because Jehoshaphat his father had been righteous before God', 'Because the temple of Solomon still stood in Jerusalem', 'a', '2 Kings 8:19 — "Yet the LORD would not destroy Judah for David his servant''s sake, as he promised him to give him alway a light, and to his children."'),
-- Adults
('2 Kings', 8, 'adults', 1, 'What is the significance of the timing when the Shunammite woman returned to petition the king, and how does the narrative present it as providential?', 'She arrived exactly as Gehazi was telling the king about her son''s resurrection, so the king was prepared to receive her petition and restored everything to her', 'She arrived during the king''s feast and so was denied at first but later received', 'She petitioned the court many times before Gehazi''s timely testimony gained her access', 'She came during a special amnesty declared by the king for returning exiles', 'a', '2 Kings 8:5-6 — "And it came to pass, as he was telling the king how he had restored a dead body to life, that, behold, the woman, whose son he had restored to life, came to cry unto the king."'),
('2 Kings', 8, 'adults', 2, 'What was the contradictory double answer Elisha gave Hazael — one part for Ben-hadad, one part of truth — and what does this reveal about prophetic communication?', 'He said to tell Ben-hadad he would recover, yet Elisha knew the king would die, meaning Ben-hadad would not die from the illness but Hazael would kill him — Elisha prophesied accurately at two levels', 'Elisha deliberately lied to Hazael to protect Ben-hadad from assassination', 'Elisha was uncertain about the outcome and gave two possibilities', 'He spoke one message in public and a secret one privately to Hazael', 'a', '2 Kings 8:10 — "And Elisha said unto him, Go, say unto him, Thou mayest certainly recover: howbeit the LORD hath shewed me that he shall surely die."'),
('2 Kings', 8, 'adults', 3, 'What was Hazael''s response when Elisha described his future atrocities against Israel — what did Hazael say about himself, and what did his question reveal?', 'He said "But what, is thy servant a dog, that he should do this great thing?" — showing he did not yet conceive of himself as capable of such evil', 'He embraced the prophecy with pride and promised to surpass Elisha''s predictions', 'He wept and asked God for forgiveness before returning to Damascus', 'He threatened Elisha''s life for speaking against Syria', 'a', '2 Kings 8:13 — "And Hazael said, But what, is thy servant a dog, that he should do this great thing? And Elisha answered, The LORD hath shewed me that thou shalt be king over Syria."'),
('2 Kings', 8, 'adults', 4, 'What events involving Edom and Libnah occurred during Jehoram of Judah''s reign, in fulfillment of which prophetic tradition?', 'Edom revolted from under the hand of Judah and made a king over themselves, and Libnah revolted at the same time, fulfilling the word spoken to Esau that he would break Jacob''s yoke', 'Edom became a vassal of Syria and Libnah was conquered by the Philistines', 'Edom paid tribute to Judah in grain and Libnah offered military alliance', 'Edom was destroyed by Jehoram and Libnah was incorporated into Judah', 'a', '2 Kings 8:20-22 — "In his days Edom revolted from under the hand of Judah, and made a king over themselves... Yet Edom revolted from under the hand of Judah unto this day. Then Libnah revolted at the same time."'),
('2 Kings', 8, 'adults', 5, 'What is the Deuteronomistic historian''s theological explanation for why the Davidic dynasty survived despite Jehoram''s evil?', 'God preserved Judah for David''s sake because of the lamp/light promise — an unconditional dynastic covenant that persisted despite individual kings'' failures', 'Jehoram secretly repented at the end of his reign and God forgave him', 'The people of Judah revolted against Jehoram''s wickedness and this pleased God', 'God was waiting for a righteous king to arise before judging the dynasty', 'a', '2 Kings 8:19 — "Yet the LORD would not destroy Judah for David his servant''s sake, as he promised him to give him alway a light, and to his children."'),
('2 Kings', 8, 'adults', 6, 'How does Ahaziah king of Judah''s moral profile in 2 Kings 8 reflect the corruption of the Davidic line through Ahab''s family?', 'He walked in the ways of the house of Ahab because his mother was Ahab''s daughter, and did evil, going to war with Joram son of Ahab against Hazael', 'He was the most righteous of Judah''s kings despite his Israelite connections', 'He rejected the house of Ahab''s influence and followed David''s ways', 'He was too young to rule effectively but the elders kept him from the worst sins', 'a', '2 Kings 8:27 — "And he walked in the way of the house of Ahab, and did evil in the sight of the LORD, as did the house of Ahab: for he was the son in law of the house of Ahab."'),
('2 Kings', 8, 'adults', 7, 'What battle brought both Joram of Israel and Ahaziah of Judah together at Ramoth-gilead, and what was the outcome for Joram?', 'They fought against Hazael king of Syria at Ramoth-gilead and Joram was wounded and returned to Jezreel to be healed of his wounds', 'They achieved a great victory over Syria and divided the spoil at Jezreel', 'Both kings were captured by Hazael and ransomed back by their children', 'Joram was killed in the battle and Ahaziah fled to Jerusalem', 'a', '2 Kings 8:28-29 — "And he went with Joram the son of Ahab to the war against Hazael king of Syria in Ramoth-gilead; and the Syrians wounded Joram."'),
('2 Kings', 8, 'adults', 8, 'What structural purpose does chapter 8 serve in the overall narrative of 2 Kings chapters 8-12?', 'It introduces the characters and political situations — Hazael''s rise, Jehoram and Ahaziah''s reigns, and Joram''s wounding — that make Jehu''s revolution in chapters 9-10 historically intelligible', 'It serves primarily as a genealogical record of Davidic succession', 'It provides economic context for the financial reforms of Joash in chapters 11-12', 'It is a standalone account of Elisha''s political ministry with no connection to later events', 'a', '2 Kings 8 — The chapter sets up the convergence of wounded Joram in Jezreel and Ahaziah''s presence there, which becomes the setting for Jehu''s coup in chapter 9.');

-- ═══ 2 Kings Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 9, 'kids', 1, 'Who was secretly anointed as king of Israel by a young prophet sent by Elisha?', 'Jehu the son of Jehoshaphat', 'Elisha''s servant Gehazi', 'A captain named Bidkar', 'Joram''s chief officer', 'a', '2 Kings 9:6 — "And he arose, and went into the house; and he poured the oil on his head, and said unto him, Thus saith the LORD God of Israel, I have anointed thee king over Israel."'),
('2 Kings', 9, 'kids', 2, 'What was Jehu famous for doing while driving his chariot?', 'He drove furiously', 'He drove slowly and carefully', 'He drove standing up on the chariot', 'He drove with only one hand', 'a', '2 Kings 9:20 — "And the driving is like the driving of Jehu the son of Nimshi; for he driveth furiously."'),
('2 Kings', 9, 'kids', 3, 'What happened to the wicked queen Jezebel at the end of this chapter?', 'She was thrown from a window and dogs ate her body', 'She fled to Syria and was never found', 'She was arrested and put in prison', 'She was burned in the palace', 'a', '2 Kings 9:33,36 — Jezebel was thrown down from a window, and the dogs ate her flesh, according to the word of the LORD.'),
-- Teens
('2 Kings', 9, 'teens', 1, 'What task did Elisha give to the young prophet he sent to Ramoth-gilead, and what was he told to do after anointing Jehu?', 'Anoint Jehu king over Israel and then flee and tarry not', 'Deliver a letter to Jehu and wait for his response', 'Anoint Jehu and then preach against the house of Ahab publicly', 'Carry oil to Jehu and let the captains decide if he was worthy', 'a', '2 Kings 9:3 — "Then take the box of oil, and pour it on his head, and say, Thus saith the LORD, I have anointed thee king over Israel. Then open the door, and flee, and tarry not."'),
('2 Kings', 9, 'teens', 2, 'When Joram''s watchman reported that the approaching driver''s driving was like Jehu''s furious driving, what had happened to the two mounted messengers sent to meet Jehu?', 'They both joined Jehu''s company and did not return', 'They returned and reported peace was given', 'They were killed by Jehu''s archers', 'They fled in the opposite direction', 'a', '2 Kings 9:18-20 — Both messengers asked "Is it peace?" and Jehu answered "What hast thou to do with peace? turn thee behind me," and both joined him and did not return.'),
('2 Kings', 9, 'teens', 3, 'What prophecy was fulfilled when Jehu killed Joram with an arrow?', 'The blood of Naboth the Jezreelite and the blood of the servants of the LORD was avenged in the portion of Jezreel', 'The word Elijah spoke at the entrance to Jezreel was fulfilled', 'Elisha''s prophecy that Joram would die in battle against Syria was fulfilled', 'The judgment God spoke to Moses about the house of Jeroboam came upon Ahab''s house', 'a', '2 Kings 9:26 — "Surely I have seen yesterday the blood of Naboth, and the blood of his sons, saith the LORD; and I will requite thee in this plat, saith the LORD."'),
('2 Kings', 9, 'teens', 4, 'What did Jezebel do when she heard Jehu had come to Jezreel, before being thrown from the window?', 'She painted her face, tired her head, and looked out at a window', 'She put on armour and prepared the palace guard for battle', 'She prayed to Baal for protection and fled to an inner chamber', 'She sent a message to Jehu offering to make peace', 'a', '2 Kings 9:30 — "And when Jehu was come to Jezreel, Jezebel heard of it; and she painted her face, and tired her head, and looked out at a window."'),
('2 Kings', 9, 'teens', 5, 'What did Jezebel call Jehu as he approached, in reference to another treacherous official from Israel''s history?', 'Zimri, thou murderer of his master', 'Omri''s son, thou rebel against kings', 'Joram''s assassin, thou man of blood', 'Ahab''s enemy, thou troubler of Israel', 'a', '2 Kings 9:31 — "And as Jehu entered in at the gate, she said, Had Zimri peace, who slew his master?"'),
-- Adults
('2 Kings', 9, 'adults', 1, 'What were the exact words of the anointing oracle delivered by the young prophet that specified the divine mandate for Jehu''s kingship?', 'Thus saith the LORD God of Israel, I have anointed thee king over the people of the LORD, even over Israel, and thou shalt smite the house of Ahab thy master, that I may avenge the blood of my servants the prophets and the blood of all the servants of the LORD', 'I anoint thee to rule Israel and to make peace with Syria and to restore the land', 'The LORD has chosen thee from all the captains to reign in righteousness over Jacob', 'Be king over my people Israel and walk in the way of David and thou shalt prosper', 'a', '2 Kings 9:6-7 — "Thus saith the LORD God of Israel, I have anointed thee king over the people of the LORD, even over Israel. And thou shalt smite the house of Ahab thy master, that I may avenge the blood of my servants the prophets."'),
('2 Kings', 9, 'adults', 2, 'How did Jehu''s fellow officers respond when he told them what the young prophet had said, and what did they do with their garments?', 'They hasted and took every man his garment and put it under Jehu on the bare stairs and blew with trumpets saying Jehu is king', 'They were silent and waited three days before declaring loyalty to Jehu', 'They were divided — half followed Jehu and half remained loyal to Joram', 'They fell on their faces before Jehu and swore an oath of silence about the anointing', 'a', '2 Kings 9:13 — "Then they hasted, and took every man his garment, and put it under him on the top of the stairs, and blew with trumpets, saying, Jehu is king."'),
('2 Kings', 9, 'adults', 3, 'What was the precise manner of Joram''s death and the theological interpretation Jehu attached to the location where Joram''s body was cast?', 'Jehu drew his bow and smote Joram between his arms and the arrow went out at his heart; Jehu commanded the body to be cast in the field of Naboth as fulfillment of the LORD''s oracle about Naboth''s blood', 'Joram was stabbed at the city gate and his body was cast into the dungeon', 'Jehu called fire from heaven that consumed Joram as Elijah had done to the captains', 'Joram fell from his chariot and Jehu''s servants completed the execution with swords', 'a', '2 Kings 9:24,26 — "And Jehu drew a bow with his full strength, and smote Jehoram between his arms, and the arrow went out at his heart... cast him in the portion of the field of Naboth the Jezreelite."'),
('2 Kings', 9, 'adults', 4, 'What question did Jehu pose to Bidkar his captain about the prophecy of Naboth, and which prophet''s oracle did he invoke?', 'He said remember how Elijah spoke burden against Ahab, and God said he would requite Ahab in Naboth''s plat for the blood of Naboth and his sons', 'He invoked Moses'' law of blood vengeance as justification for killing Joram', 'He cited the oracle of Micaiah who had predicted Ahab''s death in battle', 'He quoted the writing of Jehu son of Hanani against the house of Baasha as precedent', 'a', '2 Kings 9:25-26 — "Then said Jehu to Bidkar his captain, Take up, and cast him in the portion of the field of Naboth the Jezreelite: for remember how that, when I and thou rode together after Ahab his father, the LORD laid this burden upon him."'),
('2 Kings', 9, 'adults', 5, 'How did Ahaziah king of Judah die in the account, and where was he buried?', 'He was wounded by Jehu''s men in the going up to Gur by Ibleam, fled to Megiddo and died there, and was buried in Jerusalem in the sepulchre of his fathers', 'He surrendered to Jehu at Samaria and was executed in the palace courtyard', 'He fled to Egypt and died there of his wounds never to return', 'He was killed by the arrow that also wounded Joram at the vineyard of Naboth', 'a', '2 Kings 9:27-28 — "But when Ahaziah the king of Judah saw this, he fled by the way of the garden house. And Jehu followed after him, and said, Smite him also in the chariot... and he died there. And his servants carried him... to Jerusalem, and buried him in his sepulchre."'),
('2 Kings', 9, 'adults', 6, 'What does Jezebel''s application of cosmetics and her taunt at the window suggest about her character and strategy in her final moments?', 'She died as she lived — defiant, theatrically powerful, and attempting to manipulate by evoking the fate of Zimri to warn Jehu that assassins of kings never prosper', 'She was repenting of her sins and beautifying herself as a sign of submission', 'She was expecting Jehu to spare her because of her royal status as queen mother', 'She was attempting to charm Jehu romantically to convince him not to kill her', 'a', '2 Kings 9:30-31 — "She painted her face, and tired her head, and looked out at a window. And as Jehu entered in at the gate, she said, Had Zimri peace, who slew his master?"'),
('2 Kings', 9, 'adults', 7, 'What was left of Jezebel''s body when the men went to bury her, and what did this fulfill precisely?', 'They found no more of her than the skull, feet, and palms of her hands — fulfilling Elijah''s word that dogs shall eat Jezebel in the portion of Jezreel', 'Her body was completely consumed so there was nothing left to bury', 'Only her garments remained as the dogs had eaten everything else', 'Her body was intact but unrecognisable after being trampled by horses', 'a', '2 Kings 9:35-36 — "And they went to bury her: but they found no more of her than the skull, and the feet, and the palms of her hands... This is the word of the LORD, which he spake by his servant Elijah the Tishbite, saying, In the portion of Jezreel shall dogs eat the flesh of Jezebel."'),
('2 Kings', 9, 'adults', 8, 'How does the narrative of Jehu''s revolution in chapter 9 demonstrate the Deuteronomistic theology that prophetic words against evil dynasties are always fulfilled?', 'Every element — Ahab''s blood at Naboth''s field, Jezebel''s consumption by dogs, Joram''s death — is explicitly linked to earlier oracles of Elijah, showing the inevitability of divine judgment', 'The chapter shows that military coups are sometimes approved by God', 'The narrative proves that the northern kingdom was always under God''s blessing', 'The chapter teaches that prophets who anoint kings will be rewarded with political power', 'a', '2 Kings 9:26,36 — Both Joram''s death in Naboth''s field and Jezebel''s being eaten by dogs are explicitly tied back to Elijah''s oracles, the narrator noting each time "This is the word of the LORD which he spake."');

-- ═══ 2 Kings Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 10, 'kids', 1, 'Jehu sent letters demanding that the elders of Samaria choose a new king from among Ahab''s sons. What did the elders do instead?', 'They surrendered to Jehu and said they would do whatever he commanded', 'They chose the oldest son of Ahab as their new king', 'They sent an army against Jehu', 'They asked the king of Syria for help', 'a', '2 Kings 10:5 — "And he that was over the house, and he that was over the city, the elders also, and the bringers up of the children, sent to Jehu, saying, We are thy servants."'),
('2 Kings', 10, 'kids', 2, 'What was sent to Jehu in baskets from Samaria after Ahab''s seventy sons were killed?', 'The heads of Ahab''s seventy sons', 'The crowns of the princes', 'The seals and signet rings of Ahab''s family', 'Silver and gold from the palace', 'a', '2 Kings 10:7-8 — "And it came to pass, when the letter came to them, that they took the king''s sons, and slew seventy persons, and put their heads in baskets, and sent him them to Jezreel."'),
('2 Kings', 10, 'kids', 3, 'Jehu gathered all the worshippers of Baal into the temple for a special feast. What did he do to them?', 'He killed them all in the temple', 'He made them bow down to the LORD', 'He sent them out of the land as exiles', 'He put them in prison', 'a', '2 Kings 10:25 — "And it came to pass, as soon as he had made an end of offering the burnt offering, that Jehu said to the guard and to the captains, Go in, and slay them; let none come forth. And they smote them with the edge of the sword."'),
-- Teens
('2 Kings', 10, 'teens', 1, 'What test did Jehu use to determine whether the elders of Samaria were truly loyal to him?', 'He asked them to take the heads of Ahab''s sons and bring them to him by the next day at Jezreel', 'He commanded them to pay tribute of silver and gold within three days', 'He had them swear an oath on the altar of the LORD', 'He sent them to fight the Syrians as a test of their military loyalty', 'a', '2 Kings 10:6 — "Then he wrote a letter the second time to them, saying, If ye be mine, and if ye will hearken unto my voice, take ye the heads of the men your master''s sons, and come to me to Jezreel by to morrow this time."'),
('2 Kings', 10, 'teens', 2, 'How did Jehu justify the killing of Ahab''s household to the people of Jezreel after displaying the severed heads?', 'He said the LORD had fulfilled all He spoke against the house of Ahab and that he only killed Joram — the rest had been done by others in fulfillment of God''s word', 'He declared himself the righteous avenger of Naboth''s blood', 'He quoted the law of Moses regarding the punishment of idolatrous kings', 'He said the elders and people of Samaria were equally responsible for all the deaths', 'a', '2 Kings 10:9-10 — "And he said to all the people... Know now that there shall fall unto the earth nothing of the word of the LORD, which the LORD spake concerning the house of Ahab."'),
('2 Kings', 10, 'teens', 3, 'Who were the forty-two men Jehu killed on the road to Samaria when he met them, and what had they come for?', 'The brethren of Ahaziah king of Judah who had come down to greet the children of the king and the children of the queen', 'Forty-two priests of Baal travelling from Jezreel to Samaria', 'Ahab''s former military commanders returning from Ramoth-gilead', 'Syrian traders who were carrying tribute to the house of Ahab', 'a', '2 Kings 10:13-14 — "Jehu met with the brethren of Ahaziah king of Judah... And he said, Take them alive. And they took them alive, and slew them at the pit of the shearing house, even two and forty men."'),
('2 Kings', 10, 'teens', 4, 'What deceptive proclamation did Jehu make to gather all the Baal worshippers together?', 'He declared a solemn assembly for Baal, saying Ahab served Baal a little but Jehu shall serve him much', 'He announced a great feast in Baal''s honour for all the prophets of Baal', 'He sent messages that Baal had appeared to him in a vision commanding a national festival', 'He offered prizes of silver and gold to all who attended the temple of Baal', 'a', '2 Kings 10:18-19 — "And Jehu gathered all the people together, and said unto them, Ahab served Baal a little; but Jehu shall serve him much."'),
('2 Kings', 10, 'teens', 5, 'What was the spiritual failure of Jehu noted at the end of chapter 10 despite all his actions against the house of Ahab and Baal worship?', 'He departed not from the sins of Jeroboam the son of Nebat who made Israel to sin, keeping the golden calves at Bethel and Dan', 'He failed to tear down the high places throughout Israel', 'He married a daughter of a Baal worshipper against the law of Moses', 'He did not restore the temple in Jerusalem as David had commanded', 'a', '2 Kings 10:29 — "Howbeit from the sins of Jeroboam the son of Nebat, who made Israel to sin, Jehu departed not from after them, to wit, the golden calves that were in Bethel, and that were in Dan."'),
-- Adults
('2 Kings', 10, 'adults', 1, 'What was the rhetorical strategy of Jehu''s first letter to the elders of Samaria, and how did the elders'' complete capitulation serve his political purposes?', 'By proposing they crown one of Ahab''s seventy sons and fight for him, Jehu forced the elders to choose between armed resistance and submission — their surrender proved they would also execute Ahab''s sons on command', 'Jehu offered generous terms of peace to the elders to win their loyalty before marching on them', 'He threatened to destroy Samaria immediately unless they surrendered within one day', 'He promised to spare the seventy sons if the elders paid a ransom of silver and gold', 'a', '2 Kings 10:1-5 — Jehu''s letter challenged them to fight; their terrified reply — "We are thy servants, and will do all that thou shalt bid us" — set up the second letter demanding the heads.'),
('2 Kings', 10, 'adults', 2, 'How many members of Ahab''s extended household, allies, acquaintances, and priests did Jehu kill in Jezreel, and what theological verdict does the narrator attach to this?', 'He slew all that remained of the house of Ahab in Jezreel, all his great men and his acquaintance and his priests, until he left him none remaining, fulfilling Elijah''s prophecy', 'He killed exactly seventy sons and spared the household servants', 'He killed three hundred men of war from Ahab''s household but let the priests flee', 'He killed everyone in Jezreel except the family members who converted to serve the LORD', 'a', '2 Kings 10:11 — "So Jehu slew all that remained of the house of Ahab in Jezreel, and all his great men, and his kinsfolks, and his priests, until he left him none remaining."'),
('2 Kings', 10, 'adults', 3, 'Who was Jehonadab the son of Rechab, and what role did he play in Jehu''s reform program?', 'He was invited by Jehu to witness that Jehu was zealous for the LORD, and he joined Jehu in the chariot before the destruction of Baal worship', 'He was Jehu''s chief priest who performed the burnt offering in the Baal temple', 'He was a military captain who commanded the guard during the Baal temple massacre', 'He was the scribe who recorded Jehu''s deeds in the chronicles of Israel', 'a', '2 Kings 10:15-16 — "And when he was departed thence, he lighted on Jehonadab the son of Rechab coming to meet him... and he took him up to him into the chariot. And he said, Come with me, and see my zeal for the LORD."'),
('2 Kings', 10, 'adults', 4, 'What specific security measures did Jehu implement to ensure no Baal worshippers escaped the temple massacre?', 'He posted eighty men outside telling them any man who escaped would be killed in exchange for his own life, and before killing the worshippers he verified no servants of the LORD were present', 'He locked the temple doors and set fire to the building from outside', 'He ordered the temple surrounded by a thousand soldiers with drawn swords', 'He gave the guard poison to add to the feast food before the assembly arrived', 'a', '2 Kings 10:23-24 — "And Jehu went, and Jehonadab the son of Rechab, into the house of Baal... And he said unto him that was over the vestry, Bring forth vestments for all the worshippers of Baal. And he appointed fourscore men without."'),
('2 Kings', 10, 'adults', 5, 'What was done to the temple of Baal after the massacre of its worshippers, and what was the land used for afterward?', 'They brought forth the images out of the house of Baal and burned them, broke down the house of Baal, and made it a draught house unto this day', 'They converted the temple into a house of worship for the LORD', 'They pulled down the walls but preserved the site as a memorial of judgment', 'They buried the bodies of the slain Baal worshippers in the temple courts', 'a', '2 Kings 10:26-27 — "And they brought forth the images out of the house of Baal, and burned them. And they brake down the image of Baal, and brake down the house of Baal, and made it a draught house unto this day."'),
('2 Kings', 10, 'adults', 6, 'What divine promise did God make to Jehu because of his obedience in executing judgment on the house of Ahab?', 'Thy children of the fourth generation shall sit on the throne of Israel', 'Thou shalt be remembered as the greatest king of Israel for ever', 'I will give thee peace all the days of thy life and no enemy shall prevail', 'All the land of Syria shall be given to thy children as inheritance', 'a', '2 Kings 10:30 — "And the LORD said unto Jehu, Because thou hast done well in executing that which is right in mine eyes, and hast done unto the house of Ahab according to all that was in mine heart, thy children of the fourth generation shall sit on the throne of Israel."'),
('2 Kings', 10, 'adults', 7, 'What territorial losses did Israel suffer during Jehu''s reign due to his spiritual failures, and at whose hands?', 'Hazael smote Israel in all the coasts of Israel from Jordan eastward, all the land of Gilead — the Gadites, Reubenites, Manassites — from Aroer by Arnon, even Gilead and Bashan', 'The Philistines retook all the coastal cities Israel had held since David', 'Assyria invaded and took the northern tribes into captivity during Jehu''s reign', 'Egypt invaded and took the Negev and the land of Judah as far as Jerusalem', 'a', '2 Kings 10:32-33 — "In those days the LORD began to cut Israel short: and Hazael smote them in all the coasts of Israel; From Jordan eastward, all the land of Gilead."'),
('2 Kings', 10, 'adults', 8, 'How does the theological assessment of Jehu''s reign demonstrate the complexity of divine judgment in the Deuteronomistic History — where partial obedience brings partial reward?', 'Jehu received a dynastic promise of four generations for destroying Baalism, yet suffered territorial loss because he kept Jeroboam''s calves, showing God rewards specific obedience while still judging specific disobedience', 'Jehu''s reign shows that military success always accompanies faithfulness to God', 'The account teaches that destroying idol worship is the only criterion by which kings are judged', 'Jehu is presented as fully righteous because he executed more of God''s word than any previous king', 'a', '2 Kings 10:30-33 — God praised and rewarded Jehu''s anti-Ahab revolution (v.30) while simultaneously cutting Israel short through Hazael for Jehu''s persistence in Jeroboam''s sins (vv.31-33), illustrating graduated divine accountability.');
